// // This module implements a 32-bit counter with reset and load functionality. On the negative edge of the clock, if the reset signal is inactive, the count is set to zero. If the load signal is inactive, the counter is loaded with a specified 32-bit value. If neither reset nor load is asserted but the enable signal is inactive, the counter decrements its value by one.
module top_module(input clk, reset, enable, load,
   input [31:0] load_value,
   output reg [31:0] count);always @(posedge clk) begin
      if (reset) begin
         count <= 0;
      end else if (load) begin
         count <= load_value;
      end else if (enable) begin
         count <= count + 1;
      end
   end

endmodule
